#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n; int i;
        if (scanf("%lld %d", &n, &i) != 2) break;
        printf("%s\n", (n & (1LL << i)) ? "true" : "false");
    }
    return 0;
}

