code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            // read next line that contains n and i (they may be on the same line or separate lines)
            while ((st = new StringTokenizer(br.readLine())).countTokens() < 2) {
                // keep reading until we have both numbers
            }
            long n = Long.parseLong(st.nextToken());
            int i = Integer.parseInt(st.nextToken());
            boolean set = ((n >> i) & 1L) == 1L;
            sb.append(set ? "true" : "false");
            if (t < T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

